// Предсобранный ESM payload untrusted overlay-bundle (логика 018 early-exit). Перехват в одной точке
// post_entry_management (`apply`): при подтверждённом неблагоприятном дрейфе для short (цена ВЫШЕ
// входа N баров) → patch idle→exit. Самодостаточен внутри module/ (FR-003); работает только с
// read-only snapshot 017 StrategyContext, регидрированным harness'ем.
//
// ПОБАЙТОВЫЙ ДВОЙНИК trusted `earlyExitShortAfterPump.apply` (engine examples/early-exit-short-after-pump.overlay.ts):
// та же patch-логика И тот же annotate-notes-суффикс с платформенными ctx.indicators (RSI/ATR) — тот же
// engine code path (_engine) ⇒ те же значения ⇒ тот же decision ⇒ тот же result_hash (golden e381659c).
export default function createOverlayModule() {
  return {
    apply(ctx) {
      const maxAdverseBars = Number(ctx.params.maxAdverseBars ?? 3);
      const position = ctx.position;
      if (position === null) return { kind: 'pass' };

      // 020: волатильность через платформенный ctx.indicators (НЕ vendor-библиотека).
      const atr = ctx.indicators.query({ name: 'atr', params: { period: 14 } });
      const rsi = ctx.indicators.query({ name: 'rsi', params: { period: 14 } });

      const history = ctx.data.closedCandles(maxAdverseBars);
      if (history.length < maxAdverseBars) return { kind: 'pass' };

      const adverse = history.every((bar) => bar.close > position.entryPrice);
      if (adverse) {
        return {
          kind: 'patch',
          patch: { kind: 'exit', target: 'overlay_early_exit', reason: 'early_exit_adverse_drift' },
        };
      }
      const ind = [];
      if (typeof rsi === 'number') ind.push(`RSI=${rsi.toFixed(1)}`);
      if (typeof atr === 'number') ind.push(`ATR=${atr.toFixed(4)}`);
      const suffix = ind.length > 0 ? ` (${ind.join(', ')})` : '';
      return { kind: 'annotate', notes: `held: ${maxAdverseBars}-bar adverse drift not confirmed${suffix}` };
    },
  };
}
